function my_attribute_name($handle, $key, $value = '') {
    // Get the import ID
    $import_id = wp_all_import_get_import_id();

    // Generate the option name
    $option_name = 'soflyy-' . $import_id . '-attribute-name';

    // Get the saved attributes array
    $attributes = get_option($option_name, []);

    // If $value is empty, return the value for the specified handle and key
    if (empty($value)) {
        if (isset($attributes[$handle][$key])) {
            return $attributes[$handle][$key];
        }
        return null;
    }

    // Save the value into the attributes array
    if (!isset($attributes[$handle])) {
        $attributes[$handle] = [];
    }

    $attributes[$handle][$key] = $value;

    // Update the option with the modified attributes array
    update_option($option_name, $attributes);

    return $value;
}

