function sf_helper_meta_query_lookup( $meta_key = '', $meta_value = '', $object_type = 'post', $taxonomy = '', $return_field = 'ID', $compare = '=', $custom_args = array() ) {
    if ( empty( $object_type ) || empty( $meta_key ) || empty( $meta_value ) ) return;
	$func = 'get_posts';

	switch ( $object_type ) {
		case 'user':
			$func = 'get_users';
			break;
		case 'term':
			$func = 'get_terms';
			if ( $return_field == 'ID' ) {
				$return_field = 'term_id';
			}
			break;
		default:
			$func = 'get_posts';
			break;
	}

	if ( ! empty( $custom_args ) ) {
		$objects = $func( $custom_args );
		if ( ! empty( $objects ) ) {
			return $objects[0]->$return_field;
		} else {
			return false;
		}
	}

	$args = array();

	$meta_query = array( array(
		'key'     => $meta_key,
		'value'   => $meta_value,
		'compare' => $compare
	) );

	if ( $func == 'get_terms' ) {
		$args = array(
			'taxonomy'   => $taxonomy,
			'hide_empty' => false,
			'meta_query' => $meta_query
		);
	} elseif ( $func == 'get_users' ) {
		$args = array( 
			'meta_query' => $meta_query
		);
	} else {
		$args = array(
			'post_type'  => $object_type,
			'meta_query' => $meta_query
		);
	}

    if ( $objects = $func( $args ) ) {
