/**
 * This function filters orders by multiple criteria:
 * - Only export orders that came in before the year 2018
 * - Only export orders with "wc-processing" or "wc-completed" as the status
 * - Only export orders that have at least 1 product in the "Heart Shaped" product category
 * 
 * You need to make the following changes:
 * - Change "2" to your export ID.
 * - Change "Heart Shaped" to the category you want to be exported.
 * - Change "2018-01-01 00:00:00" and/or the date comparison to match the date(s) you want.
 * 
 * !!! IMPORTANT NOTES !!!
 * - The "Display each product in its own row" option in the export template must be ENABLED.
 * - The "Fill in empty columns" option in the export template must be DISABLED.
 * - The "my_check_if_in_product_cat" helper function below must be saved in the function editor as well.
 * - The export count won't change, but only the filtered orders will be in the final export file.
 */
function my_wp_all_export_csv_rows( $articles, $options, $export_id ) {
    // Only run for export ID 2
    if ( $export_id != 2 ) {
        return $articles;
    }

    // Set up an array to store the orders that pass the filters.
	$allowed_orders = array();

    // Loop through each export record
    foreach ( $articles as $key => $article ) {
        // Get the data we need for our filters.
		$date   = $article['Order Date'];
		$status = $article['Order Status'];
		$in_cat = my_check_if_in_product_cat( $article['Product ID'], 'Heart Shaped' );

        // If status is not wc-processing or wc-completed, do not add to allowed orders.
		if ( $status != 'wc-processing' && $status != 'wc-completed' ) {
			continue;
		}

        // If product is not in the "Heart Shaped" category, do not add to allowed orders.
		if ( $in_cat == false ) {
			continue;
		}

        // If order date is in 2018 or newer, do not add to allowed orders.
		if ( strtotime( $date ) >= strtotime( '2018-01-01 00:00:00' ) ) {
			continue;
		}

        // If the code gets here, the order ID passed all of the checks, so we add it to allowed orders.
		$allowed_orders[] = $article['Order ID'];
	}

	// Remove all disallowed orders.
	foreach ( $articles as $key => $article ) {
		if ( ! in_array( $article['Order ID'], $allowed_orders ) ) {
			unset( $articles[ $key ] );	
		}
	}

	// Return the allowed orders.
	return isset($articles[0]) ? $articles : $articles[0] = [];
}
add_filter( 'wp_all_export_csv_rows', 'my_wp_all_export_csv_rows', 10, 3 );

// Checks if a product is in a specified category.
function my_check_if_in_product_cat( $item_id = array(), $category = '' ) {
	if ( empty( $category ) || empty( $item_id ) ) {
		return false;
	}

	$terms = get_the_terms( $item_id, 'product_cat' );

	foreach ( $terms as $term ) {
		if ( $category == $term->name ) {
			return true;
		} else {
			continue;
		}
	}
	return false;
}

