function my_nested_data($parent_repeater_name = "", $nested_repeater_name = "", $field_name = "", $post_id = null, $image = false, $separator = "|") {
    $output = [];
    if( have_rows($parent_repeater_name, $post_id) ) {
        while( have_rows($parent_repeater_name, $post_id) ) {
            the_row();
            $nested_output = []; // Initialize an array to hold nested repeater field data
            if( have_rows($nested_repeater_name, $post_id) ) {
                while( have_rows($nested_repeater_name, $post_id) ) {
                    the_row();
                    $field_data = get_sub_field($field_name);
                    if ($image && filter_var($field_data, FILTER_VALIDATE_URL) === FALSE) {
                        $field_data = (is_array($field_data) && isset($field_data['url'])) ? $field_data['url'] : $field_data;
                    }
                    $nested_output[] = $field_data; // Add to the nested output array
                }
            }
            $output[] = implode(';', $nested_output); // Implode nested data with ';' and add to the main output array
        }
    }
    return implode($separator, $output); // Implode the main output array with '|'
}

