function soflyy_img_import( $post_id, $gallery_attachment_ids, $missing_images ) {
    // Check if there are any missing images to process
    if ( empty($missing_images) ) {
        return; // Exit if no missing images are found
    }

    // Ensure the featured image is not considered for deletion
    $thumbnail_id = get_post_thumbnail_id( $post_id );
    if (!in_array($thumbnail_id, $gallery_attachment_ids)) {
        $gallery_attachment_ids[] = $thumbnail_id;
    }

    // Identify the actual images to delete
    $images_to_delete = array_diff($missing_images, $gallery_attachment_ids);

    // Delete the identified images
    foreach ($images_to_delete as $image_id) {
        wp_delete_attachment($image_id, true);
    }
}
