function my_add_custom_fields_to_variations($parent_product_id) {
    $temp_custom_field_name = "_temp_variation_custom_field";
    $variant_custom_field_name = "woo_feed_ean";

    // Get the parent product object
    $parent_product = wc_get_product($parent_product_id);

    // Check if the parent product exists and is a variable product
    if (!$parent_product || 'variable' !== $parent_product->get_type()) {
        return;
    }

    // Get the comma-separated string from the parent product's custom field
    $custom_field_values_string = get_post_meta($parent_product_id, $temp_custom_field_name, true);

    // Convert the string to an array
    $custom_field_values = explode(',', $custom_field_values_string);

    // Get all variations of the parent product
    $variation_ids = $parent_product->get_children();

    // Iterate through each variation and assign the corresponding custom field value
    foreach ($variation_ids as $index => $variation_id) {
        if (isset($custom_field_values[$index])) {
            // Update the custom field for the variation
            update_post_meta($variation_id, $variant_custom_field_name, trim($custom_field_values[$index]));
        }
    }

    // Optionally, delete the custom field from the parent product at the end
    delete_post_meta($parent_product_id, $temp_custom_field_name);
}

